import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as n,c as s,e}from"./app-be253e4c.js";const o={},c=e(`<h1 id="ifconfig命令" tabindex="-1"><a class="header-anchor" href="#ifconfig命令" aria-hidden="true">#</a> ifconfig命令</h1><p><code>ifconfig</code>代表<code>interface configuration</code>，其用于查看和更改系统上网络接口的配置。</p><h2 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h2><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ifconfig</span> <span class="token punctuation">[</span>-a<span class="token punctuation">]</span> <span class="token punctuation">[</span>-v<span class="token punctuation">]</span> <span class="token punctuation">[</span>-s<span class="token punctuation">]</span> <span class="token operator">&lt;</span>interface<span class="token operator">&gt;</span> <span class="token punctuation">[</span><span class="token punctuation">[</span><span class="token operator">&lt;</span>AF<span class="token operator">&gt;</span><span class="token punctuation">]</span> <span class="token operator">&lt;</span>address<span class="token operator">&gt;</span><span class="token punctuation">]</span>
  <span class="token punctuation">[</span>add <span class="token operator">&lt;</span>address<span class="token operator">&gt;</span><span class="token punctuation">[</span>/<span class="token operator">&lt;</span>prefixlen<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">]</span>
  <span class="token punctuation">[</span>del <span class="token operator">&lt;</span>address<span class="token operator">&gt;</span><span class="token punctuation">[</span>/<span class="token operator">&lt;</span>prefixlen<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">]</span>
  <span class="token punctuation">[</span><span class="token punctuation">[</span>-<span class="token punctuation">]</span>broadcast <span class="token punctuation">[</span><span class="token operator">&lt;</span>address<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">]</span>  <span class="token punctuation">[</span><span class="token punctuation">[</span>-<span class="token punctuation">]</span>pointopoint <span class="token punctuation">[</span><span class="token operator">&lt;</span>address<span class="token operator">&gt;</span><span class="token punctuation">]</span><span class="token punctuation">]</span>
  <span class="token punctuation">[</span>netmask <span class="token operator">&lt;</span>address<span class="token operator">&gt;</span><span class="token punctuation">]</span>  <span class="token punctuation">[</span>dstaddr <span class="token operator">&lt;</span>address<span class="token operator">&gt;</span><span class="token punctuation">]</span>  <span class="token punctuation">[</span>tunnel <span class="token operator">&lt;</span>address<span class="token operator">&gt;</span><span class="token punctuation">]</span>
  <span class="token punctuation">[</span>outfill <span class="token operator">&lt;</span>NN<span class="token operator">&gt;</span><span class="token punctuation">]</span> <span class="token punctuation">[</span>keepalive <span class="token operator">&lt;</span>NN<span class="token operator">&gt;</span><span class="token punctuation">]</span>
  <span class="token punctuation">[</span>hw <span class="token operator">&lt;</span>HW<span class="token operator">&gt;</span> <span class="token operator">&lt;</span>address<span class="token operator">&gt;</span><span class="token punctuation">]</span>  <span class="token punctuation">[</span>mtu <span class="token operator">&lt;</span>NN<span class="token operator">&gt;</span><span class="token punctuation">]</span>
  <span class="token punctuation">[</span><span class="token punctuation">[</span>-<span class="token punctuation">]</span>trailers<span class="token punctuation">]</span>  <span class="token punctuation">[</span><span class="token punctuation">[</span>-<span class="token punctuation">]</span>arp<span class="token punctuation">]</span>  <span class="token punctuation">[</span><span class="token punctuation">[</span>-<span class="token punctuation">]</span>allmulti<span class="token punctuation">]</span>
  <span class="token punctuation">[</span>multicast<span class="token punctuation">]</span>  <span class="token punctuation">[</span><span class="token punctuation">[</span>-<span class="token punctuation">]</span>promisc<span class="token punctuation">]</span>
  <span class="token punctuation">[</span>mem_start <span class="token operator">&lt;</span>NN<span class="token operator">&gt;</span><span class="token punctuation">]</span>  <span class="token punctuation">[</span>io_addr <span class="token operator">&lt;</span>NN<span class="token operator">&gt;</span><span class="token punctuation">]</span>  <span class="token punctuation">[</span>irq <span class="token operator">&lt;</span>NN<span class="token operator">&gt;</span><span class="token punctuation">]</span>  <span class="token punctuation">[</span>media <span class="token operator">&lt;</span>type<span class="token operator">&gt;</span><span class="token punctuation">]</span>
  <span class="token punctuation">[</span>txqueuelen <span class="token operator">&lt;</span>NN<span class="token operator">&gt;</span><span class="token punctuation">]</span>
  <span class="token punctuation">[</span><span class="token punctuation">[</span>-<span class="token punctuation">]</span>dynamic<span class="token punctuation">]</span>
  <span class="token punctuation">[</span>up<span class="token operator">|</span>down<span class="token punctuation">]</span> <span class="token punctuation">..</span>.
</code></pre></div><h2 id="参数" tabindex="-1"><a class="header-anchor" href="#参数" aria-hidden="true">#</a> 参数</h2><ul><li><code>(none), -a</code>: 显示所有网络接口的信息，即使它们已关闭。</li><li><code>-s</code>: 以与命令<code>netstat -i</code>相同的格式显示简短列表。</li><li><code>-v</code>: 详细模式，显示某些错误情况的详细信息。</li><li><code>interface</code>: 接口名称，通常是驱动程序名称，后跟一个单元号，例如第一个以太网接口的<code>eth0</code>，如果内核支持别名接口，则可以为<code>eth0</code>的第一个别名使用<code>eth0:0</code>指定它们，可以使用它们来分配第二个地址，要删除别名接口，可以使用<code>ifconfig eth0：0 down</code>，注意如果删除第一个(主接口)，则对于每个范围即具有地址/网络掩码组合的同一网络，所有别名都将被删除。</li><li><code>up</code>: 该标志导致接口被激活，如果为接口分配了地址，则隐式指定。</li><li><code>down</code>: 该标志导致该接口的驱动程序被关闭。</li><li><code>[-]arp</code>: 在此接口上启用(指定了<code>-</code>前缀则禁用)<code>ARP</code>协议的使用。</li><li><code>[-]promisc</code>: 启用(指定了<code>-</code>前缀则禁用)接口的混杂模式，如果启用混杂模式，接口将接收网络上的所有数据包。</li><li><code>[-]allmulti</code>: 启用(指定了<code>-</code>前缀则禁用)全组播模式，启用组播模式后，该接口将接收网络上所有的组播报文。</li><li><code>metric N</code>: 此参数设置接口度量，接口使用该度量做出路由决策，<code>N</code>必须是介于<code>0</code>和<code>4294967295</code>之间的整数。</li><li><code>mtu N</code>: 该参数用于设置接口的最大传输单元，该设置用于限制接口传输的最大数据包大小。</li><li><code>dstaddr address</code>: 为点到点链路(如<code>PPP</code>)设置远程<code>IP</code>地址，此关键字现在已过时，请改用<code>pointopoint</code>关键字。</li><li><code>netmask address</code>: 设置接口的<code>IP</code>网络掩码，该值默认为通常的<code>A</code>、<code>B</code>或<code>C</code>类网络掩码(从接口<code>IP</code>地址派生)，但它可以设置为任何值。</li><li><code>add address/prefixlen</code>: 在接口上添加<code>IPv6</code>地址。</li><li><code>del address/prefixlen</code>: 从接口移除<code>IPv6</code>地址。</li><li><code>tunnel aa.bb.cc.dd</code>: 创建一个新的<code>SIT (IPv6-in-IPv4)</code>设备，通过隧道传送到给定的目的地。</li><li><code>irq address</code>: 设置此设备使用的中断线，并非所有设备都可以动态更改其<code>IRQ</code>设置。</li><li><code>io_addr address</code>: 在此设备的<code>I/O</code>空间中设置起始地址。</li><li><code>mem_start address</code>: 设置此设备使用的共享内存的起始地址，仅少数设备需要此功能。</li><li><code>media type</code>: 设置设备要使用的物理端口或介质类型，并非所有设备都可以更改此设置，并且某些设备可以更改其支持的值，类型的典型值是<code>10base2</code>(细缆网)、<code>10baseT</code>(双绞线<code>10 Mbps</code>以太网)、<code>AUI</code>外部收发器等，<code>auto</code>的特殊介质类型告诉驱动程序自动感知介质，同样并非所有驱动程序都可以执行此操作。</li><li><code>[-]broadcast [address]</code>: 如果指定了地址参数，则将为此接口设置协议广播地址，否则它将设置(指定了<code>-</code>前缀则清除)接口的<code>IFF_BROADCAST</code>标志。</li><li><code>[-]pointopoint [address]</code>: 这个关键字启用了接口的点对点模式，这意味着它是两台机器之间的直接链接，没有其他人监听它，如果还提供了<code>address</code>参数，请设置链接另一端的协议地址，就像过时的<code>dstaddr</code>关键字一样，否则，设置或清除接口的<code>IFF POINTOPOINT</code>标志。</li><li><code>hw class address</code>: 如果设备驱动程序支持此操作，则设置此接口的硬件地址，关键字之后必须是硬件类的名称以及与硬件地址等效的可打印<code>ASCII</code>。当前支持的硬件类别包括以太<code>ether (Ethernet)</code>、<code>ax25 (AMPR AX.25)</code>、<code>ARCnet and netrom (AMPR NET/ROM)</code>。</li><li><code>multicast</code>: 在接口上设置多播标志，由于驱动程序自己会正确设置该标志，因此通常不需要这样做。</li><li><code>address</code>: 分配给该接口的<code>IP</code>地址。</li><li><code>txqueuelen length</code>: 设置设备发送队列的长度，对于具有较高延迟的较慢设备(例如通过调制解调器或<code>ISDN</code>进行的连接)将其设置为较小的值非常有用，以防止快速的批量传输过多地干扰诸如<code>telnet</code>之类的交互式通信。</li></ul><h3 id="硬体类型" tabindex="-1"><a class="header-anchor" href="#硬体类型" aria-hidden="true">#</a> 硬体类型</h3><p><code>loop (Local Loopback)</code>、<code>slip (Serial Line IP)</code>、<code>cslip (VJ Serial Line IP)</code>、<code>slip6 (6-bit Serial Line IP)</code>、<code>cslip6 (VJ 6-bit Serial Line IP)</code>、<code>adaptive (Adaptive Serial Line IP)</code>、<code>ash (Ash)</code>、<code>ether (Ethernet)</code>、<code>ax25 (AMPR AX.25)</code>、<code>netrom (AMPR NET/ROM)</code>、<code>rose (AMPR ROSE)</code>、<code>tunnel (IPIP Tunnel)</code>、<code>ppp (Point-to-Point Protocol)</code>、<code>hdlc ((Cisco)-HDLC)</code>、<code>lapb (LAPB)</code>、 <code>arcnet (ARCnet)</code>、<code>dlci (Frame Relay DLCI)</code>、<code>frad (Frame Relay Access Device)</code>、<code>sit (IPv6-in-IPv4)</code>、<code>fddi (Fiber Distributed Data Interface)</code>、<code>hippi (HIPPI)</code>、<code>irda (IrLAP)</code>、<code>ec (Econet)</code>、<code>x25 (generic X.25)</code>、<code>eui64 (Generic EUI-64)</code></p><h3 id="地址族" tabindex="-1"><a class="header-anchor" href="#地址族" aria-hidden="true">#</a> 地址族</h3><p><code>unix (UNIX Domain)</code>、<code>inet (DARPA Internet)</code>、<code>inet6 (IPv6)</code>、<code>ax25 (AMPR AX.25)</code>、<code>netrom (AMPR NET/ROM)</code>、<code>rose (AMPR ROSE)</code>、<code>ipx (Novell IPX)</code>、<code>ddp (Appletalk DDP)</code>、<code>ec (Econet)</code>、<code>ash (Ash)</code>、<code>x25 (CCITT X.25)</code></p><h2 id="示例" tabindex="-1"><a class="header-anchor" href="#示例" aria-hidden="true">#</a> 示例</h2><p>显示网络设备信息。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ifconfig</span>
</code></pre></div><p>启动关闭指定网卡。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ifconfig</span> eth0 down
<span class="token function">ifconfig</span> eth0 up
</code></pre></div><p>为网卡配置和删除<code>IPv6</code>地址。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ifconfig</span> eth0 <span class="token function">add</span> 33ffe:3240:800:1005::2/ <span class="token number">64</span>
<span class="token function">ifconfig</span> eth0 del 33ffe:3240:800:1005::2/ <span class="token number">64</span>
</code></pre></div><p>修改<code>MAC</code>地址，需要首先关闭网卡并修改<code>MAC</code>地址，之后再开启网卡。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ifconfig</span> eth1 hw ether 00:1D:1C:1D:1E
<span class="token function">ifconfig</span> eth1 up
</code></pre></div><p>为网卡配置<code>IP</code>地址，并加上子掩码以及广播地址。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ifconfig</span> eth0 <span class="token number">192.168</span>.1.56 netmask <span class="token number">255.255</span>.255.0 broadcast <span class="token number">192.168</span>.1.255
</code></pre></div><p>启用和关闭<code>ARP</code>协议。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ifconfig</span> eth0 arp
<span class="token function">ifconfig</span> eth0 <span class="token parameter variable">-arp</span>
</code></pre></div><p>设置最大传输单元<code>MTU</code>。</p><div class="language-bash" data-ext="sh"><pre class="language-bash"><code><span class="token function">ifconfig</span> eth0 mtu <span class="token number">1500</span> 
</code></pre></div>`,25),t=[c];function p(d,l){return n(),s("div",null,t)}const u=a(o,[["render",p],["__file","ifconfig.html.vue"]]);export{u as default};
